function translateString(thStr) {
    if (!thStr) return thStr;
    
    // Normalize whitespace to match dictionary keys (e.g., handle newlines in HTML)
    const normalized = thStr.replace(/\s+/g, ' ').trim();
    if (th2en[normalized]) {
        // Preserve leading and trailing whitespace from the original string
        const leadingMatch = thStr.match(/^\s*/);
        const trailingMatch = thStr.match(/\s*$/);
        const leading = leadingMatch ? leadingMatch[0] : '';
        const trailing = trailingMatch ? trailingMatch[0] : '';
        return leading + th2en[normalized] + trailing;
    }
    
    // Check partial replacement for dynamic strings like names or compound job titles
    const prefixes = ['ผู้จัดการแผนก ', 'เจ้าหน้าที่แผนก ', 'พนักงานประจำ ', 'หัวหน้าแผนก '];
    for (const prefix of prefixes) {
        if (normalized.startsWith(prefix)) {
            const rest = normalized.substring(prefix.length).trim();
            const translatedPrefix = th2en[prefix.trim()] + ' ';
            const translatedRest = th2en[rest] || rest;
            return thStr.replace(normalized, translatedPrefix + translatedRest);
        }
    }
    
    return thStr;
}

window.I18n = {
    observer: null,
    translate: translateString,

    applyTranslations(root = document.body) {
        let isEn = false;
        if (typeof App !== 'undefined' && App.settings) {
            isEn = App.settings.language === 'en';
        }

        document.documentElement.lang = isEn ? 'en' : 'th';
        document.body.classList.toggle('lang-en', isEn);

        const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, null, false);
        const textNodes = [];
        let node;
        while (node = walker.nextNode()) {
            const parent = node.parentElement;
            if (!parent || parent.isContentEditable || parent.tagName === "SCRIPT" || parent.tagName === "STYLE" || parent.closest("#profile-lang-text") || parent.closest(".member-name") || parent.closest(".project-name-display") || parent.id === "current-user-name" || parent.id === "up-name" || parent.id === "up-full-name" || parent.id === "up-nickname") continue;

            let text = node.nodeValue;
            if (text.trim().length > 0) {
                textNodes.push(node);
            }
        }

        textNodes.forEach(node => {
            if (node._originalTh === undefined) {
                node._originalTh = node.nodeValue;
            }

            if (isEn) {
                const trans = translateString(node._originalTh);
                if (node.nodeValue !== trans) node.nodeValue = trans;
            } else {
                if (node.nodeValue !== node._originalTh) node.nodeValue = node._originalTh;
            }
        });

        const inputs = root.querySelectorAll ? root.querySelectorAll("input[placeholder], textarea[placeholder]") : [];
        inputs.forEach(el => {
            if (el._originalPlaceholder === undefined) {
                el._originalPlaceholder = el.placeholder;
            }
            if (isEn) {
                el.placeholder = translateString(el._originalPlaceholder);
            } else {
                el.placeholder = el._originalPlaceholder;
            }
        });

        const buttons = root.querySelectorAll ? root.querySelectorAll("input[type=\"button\"], input[type=\"submit\"]") : [];
        buttons.forEach(el => {
            if (el._originalValue === undefined) {
                el._originalValue = el.value;
            }
            if (isEn) {
                el.value = translateString(el._originalValue);
            } else {
                el.value = el._originalValue;
            }
        });
    },

    init() {
        this.applyTranslations();

        if (!this.observer) {
            this.observer = new MutationObserver(mutations => {
                let shouldTranslate = false;
                for (let m of mutations) {
                    const el = m.target.nodeType === Node.TEXT_NODE ? m.target.parentElement : m.target;
                    if (el && el.isContentEditable) continue;

                    if (m.addedNodes.length > 0) {
                        shouldTranslate = true;
                        break;
                    }
                    if (m.type === "characterData" && m.target._originalTh === undefined) {
                        shouldTranslate = true;
                        break;
                    }
                }
                if (shouldTranslate) {
                    this.observer.disconnect(); // Prevent infinite loops
                    this.applyTranslations();
                    this.observer.observe(document.body, { childList: true, subtree: true, characterData: true });
                }
            });
            this.observer.observe(document.body, { childList: true, subtree: true, characterData: true });
        }
    }
};

document.addEventListener("DOMContentLoaded", () => {
    // Wait for App to be initialized
    setTimeout(() => {
        window.I18n.init();
    }, 100);
});














